CREATE TABLE circuit_facts (
    circuit_key INTEGER UNIQUE,
    circuit_short_name TEXT PRIMARY KEY,
    canonical_name TEXT NOT NULL,
    track_length_km TEXT NOT NULL,
    race_distance_km TEXT NOT NULL,
    laps INTEGER NOT NULL,
    turns INTEGER NOT NULL,
    first_grand_prix INTEGER NOT NULL,
    direction TEXT NOT NULL,
    drs_zones INTEGER NOT NULL,
    lap_record TEXT NOT NULL,
    lap_record_holder TEXT NOT NULL,
    lap_record_year INTEGER NOT NULL,
    overtaking_hotspot TEXT NOT NULL,
    quick_fact TEXT NOT NULL,
    updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

